const body = $json.body ?? $json;
const now = new Date().toISOString();
const canonRoot = 'C:\\ServerCIT\\services\\heal-canon-intake';
const rsidRoot = 'C:\\ServerCIT\\services\\heal-rsid-resolution';
const vcfRoot = 'C:\\ServerCIT\\services\\heal-vcf-integrity\\incoming';
const outputRoot = 'C:\\ServerCIT\\services\\heal-vcf-canon-match';
function normalizePath(value) { return String(value ?? '').replace(/\//g, '\\'); }
function assertInside(root, target, label) {
  const normalizedRoot = normalizePath(root).toLowerCase();
  const normalizedTarget = normalizePath(target).toLowerCase();
  if (!normalizedTarget.startsWith(normalizedRoot + '\\')) throw new Error(`${label} is outside the allowed root.`);
}
const canonCleanPath = normalizePath(body.canonCleanPath);
const rsidReadyPath = normalizePath(body.rsidReadyPath);
const vcfPath = normalizePath(body.vcfPath);
const outputDir = normalizePath(body.outputDir);
const runId = String(body.runId ?? $execution.id);
if (!canonCleanPath || !rsidReadyPath || !vcfPath || !outputDir) throw new Error('canonCleanPath, rsidReadyPath, vcfPath, and outputDir are required.');
assertInside(canonRoot, canonCleanPath, 'canonCleanPath');
assertInside(rsidRoot, rsidReadyPath, 'rsidReadyPath');
assertInside(vcfRoot, vcfPath, 'vcfPath');
assertInside(outputRoot, outputDir, 'outputDir');
const payload = { canonCleanPath, rsidReadyPath, vcfPath, outputDir, runId };
const inputJsonBase64 = Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
const command = `powershell -NoProfile -ExecutionPolicy Bypass -File "C:\\ServerCIT\\services\\heal-vcf-canon-match\\run_heal_vcf_canon_match.ps1" -InputJsonBase64 "${inputJsonBase64}"`;
return [{ json: { accepted: true, event: 'heal.vcf_canon_match.requested', runId, canonCleanPath, rsidReadyPath, vcfPath, outputDir, command, receivedAt: now, source: 'heal-api' } }];

const stdout = String($json.stdout ?? '');
const stderr = String($json.stderr ?? '');
const lines = stdout.trim().split(/\r?\n/).filter(Boolean);
const lastLine = lines[lines.length - 1] ?? '{}';
let matchSummary;
try { matchSummary = JSON.parse(lastLine); }
catch (error) { throw new Error(`VCF canon match returned invalid JSON: ${error.message}. stderr=${stderr}`); }
const inputRoot = 'C:\\ServerCIT\\services\\heal-vcf-canon-match';
const outputRoot = 'C:\\ServerCIT\\services\\heal-match-preparation';
function normalizePath(value) { return String(value ?? '').replace(/\//g, '\\'); }
function assertInside(root, target, label) {
  const normalizedRoot = normalizePath(root).toLowerCase();
  const normalizedTarget = normalizePath(target).toLowerCase();
  if (!normalizedTarget.startsWith(normalizedRoot + '\\')) throw new Error(`${label} is outside the allowed root.`);
}
const matchRunId = $('Prepare VCF Canon Match').first().json.runId;
const runId = `match-prep-${matchRunId}`;
const inputPath = normalizePath(matchSummary.outputs?.sheetFinalConsolidatedCsv);
const outputDir = `${outputRoot}\\runs\\${runId}`;
if (!inputPath) throw new Error('sheetFinalConsolidatedCsv is required for match preparation.');
assertInside(inputRoot, inputPath, 'inputPath');
assertInside(outputRoot, outputDir, 'outputDir');
const payload = { inputPath, outputDir, runId, matchRunId };
const inputJsonBase64 = Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
const command = `powershell -NoProfile -ExecutionPolicy Bypass -File "C:\\ServerCIT\\services\\heal-match-preparation\\run_heal_match_preparation.ps1" -InputJsonBase64 "${inputJsonBase64}"`;
return [{ json: { accepted: true, event: 'heal.match_preparation.requested', runId, matchRunId, inputPath, outputDir, command, matchSummary, receivedAt: new Date().toISOString(), source: 'heal-api' } }];

const stdout = String($json.stdout ?? '');
const stderr = String($json.stderr ?? '');
const lines = stdout.trim().split(/\r?\n/).filter(Boolean);
const lastLine = lines[lines.length - 1] ?? '{}';
let preparationSummary;
try { preparationSummary = JSON.parse(lastLine); }
catch (error) { throw new Error(`Match preparation returned invalid JSON: ${error.message}. stderr=${stderr}`); }
const matchSummary = $('Prepare Match Preparation').first().json.matchSummary;
const summary = { ...matchSummary, matchPreparation: preparationSummary };
return [{ json: { accepted: summary.status === 'valid' || summary.status === 'warning', event: 'heal.vcf_canon_match.completed', runId: $('Prepare VCF Canon Match').first().json.runId, status: summary.status, summary, completedAt: new Date().toISOString(), n8n: { workflowName: 'HEAL - VCF Canon Match', executionId: $execution.id } } }];
